namespace sv_151efc2849d444ab8524542c866939c8.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Reusable message input: textarea + submit button *@

<div class="message-input">
    <textarea @bind="Text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn-send" @onclick="Submit" disabled="@string.IsNullOrWhiteSpace(Text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSubmit { get; set; }

    private string Text { get; set; } = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Submit();
        }
    }

    private async Task Submit()
    {
        if (string.IsNullOrWhiteSpace(Text)) return;
        var content = Text.Trim();
        Text = "";
        await OnSubmit.InvokeAsync(content);
    }
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #e0e0e0;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 6px;
    padding: 0.5rem 0.75rem;
    font-size: 0.875rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input textarea:focus {
    border-color: #4a76a8;
}

.btn-send {
    align-self: flex-end;
    padding: 0.5rem 1.25rem;
    background: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 6px;
    font-size: 0.875rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s;
}

.btn-send:hover:not(:disabled) {
    background: #3b6290;
}

.btn-send:disabled {
    opacity: 0.5;
    cursor: default;
}

@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-header">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-desc">@Truncate(channel.Description, 50)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public IReadOnlyList<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int max) =>
        text.Length <= max ? text : text[..max] + "…";
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background: #2c2f33;
    color: #dcddde;
    height: 100%;
    overflow-y: auto;
}

.sidebar-title {
    padding: 1rem;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    border-bottom: 1px solid #40444b;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 0.5rem 0;
}

.channel-item {
    padding: 0.5rem 1rem;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 0.5rem;
    transition: background 0.12s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #40444b;
    color: #fff;
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #96989d;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    display: block;
    margin-top: 2px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.4rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
    flex-shrink: 0;
}

@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="() => showActions = false">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <button class="reaction-badge" @onclick="() => OnReact.InvokeAsync(reaction.Emoji)"
                        title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </button>
            }
        </div>
    }

    @if (ThreadReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnOpenThread.InvokeAsync()">
            💬 @ThreadReplyCount @(ThreadReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions && ShowHoverActions)
    {
        <div class="hover-actions">
            <button class="action-btn" @onclick="() => OnOpenThread.InvokeAsync()" title="Reply in thread">💬 Reply</button>
            <div class="emoji-picker-wrapper">
                <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">😀 React</button>
                @if (showEmojiPicker)
                {
                    <div class="emoji-picker">
                        @foreach (var emoji in commonEmojis)
                        {
                            <button class="emoji-option" @onclick="() => PickEmoji(emoji)">@emoji</button>
                        }
                    </div>
                }
            </div>
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ThreadReplyCount { get; set; }
    [Parameter] public bool ShowHoverActions { get; set; } = true;
    [Parameter] public EventCallback OnOpenThread { get; set; }
    [Parameter] public EventCallback<string> OnReact { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task PickEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReact.InvokeAsync(emoji);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    padding: 0.5rem 1rem;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f9fa;
}

