    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    background: #eef1f5;
    border: 1px solid #dce0e5;
    border-radius: 12px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.12s;
}

.reaction-badge:hover {
    background: #dce0e5;
}

.thread-link {
    display: inline-block;
    margin-top: 0.35rem;
    padding: 0.2rem 0.5rem;
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.12s;
}

.thread-link:hover {
