{"path": "/tmp/sv-151efc2849d444ab8524542c866939c8/Components/Pages/Chat/ChannelSidebar.razor", "file_text": "@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
