{"path": "/tmp/sv-151efc2849d444ab8524542c866939c8/Components/Pages/Chat/MessageArea.razor", "file_text": "@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="message-area">
    <div class="area-header">
        <h2 class="area-channel-name"># @ChannelName</h2>
        <span class="area-channel-desc">@ChannelDescription</span>
    </div>

    <div class="message-list" @onscroll="HandleScroll" @ref="messageListRef">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }

        @foreach (var msg in Messages)
        {
            <MessageItem Message="msg"
                         ThreadReplyCount="GetReplyCount(msg.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(msg.Id)"
                         OnReact="(emoji) => OnReact.InvokeAsync((msg.Id, emoji))" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{ChannelName}")" OnSubmit="OnSendMessage" />
</div>

@code {
    [Parameter, EditorRequired] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter, EditorRequired] public IReadOnlyList<Message> Messages { get; set; } = [];
    [Parameter] public IReadOnlyList<ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;

    private int GetReplyCount(int messageId)
    {
        var summary = ThreadSummaries.FirstOrDefault(t => t.RootMessageId == messageId);
        return summary?.ReplyCount ?? 0;
    }

    private async Task HandleScroll()
    {
        // Scroll-to-top detection is handled via JS interop in the page
        await OnLoadMore.InvokeAsync();
    }
}
"}

