toolArgs.file_text:
@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="channel-sidebar">
    <h3 class="sidebar-title">Channels</h3>
    <ul class="channel-list">
        @foreach (var channel in Channels)
        {
            <li class="channel-item @(channel.Id == ActiveChannelId ? "active" : "")"
                @onclick="() => OnChannelSelected.InvokeAsync(channel.Id)">
                <div class="channel-header">
                    <span class="channel-name"># @channel.Name</span>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </div>
                <span class="channel-desc">@Truncate(channel.Description, 50)</span>
            </li>
        }
    </ul>
</div>

@code {
    [Parameter, EditorRequired] public IReadOnlyList<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }

    private static string Truncate(string text, int max) =>
        text.Length <= max ? text : text[..max] + "…";
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background: #2c2f33;
    color: #dcddde;
    height: 100%;
    overflow-y: auto;
}

.sidebar-title {
    padding: 1rem;
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    border-bottom: 1px solid #40444b;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 0.5rem 0;
}

.channel-item {
    padding: 0.5rem 1rem;
    cursor: pointer;
    border-radius: 4px;
    margin: 0 0.5rem;
    transition: background 0.12s;
}

.channel-item:hover {
    background: #36393f;
}

.channel-item.active {
    background: #40444b;
    color: #fff;
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 0.5rem;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.channel-desc {
    font-size: 0.75rem;
    color: #96989d;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    display: block;
    margin-top: 2px;
}

.unread-badge {
    background: #ed4245;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 0.1rem 0.4rem;
    border-radius: 10px;
    min-width: 1.2rem;
    text-align: center;
    flex-shrink: 0;
}

