.message-item {
    padding: 0.5rem 1rem;
    position: relative;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #2c2f33;
}

.timestamp {
    font-size: 0.75rem;
    color: #96989d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.4;
    color: #36393f;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    background: #eef1f5;
    border: 1px solid #dce0e5;
    border-radius: 12px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.12s;
}

.reaction-badge:hover {
    background: #dce0e5;
}

.thread-link {
    display: inline-block;
    margin-top: 0.35rem;
    padding: 0.2rem 0.5rem;
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.12s;
}

.thread-link:hover {
    background: #eef1f5;
}

.hover-actions {
    position: absolute;
    top: -0.75rem;
    right: 0.75rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dce0e5;
    border-radius: 6px;
    padding: 0.2rem;
    box-shadow: 0 2px 6px rgba(0,0,0,0.1);
    z-index: 10;
}

.action-btn {
    padding: 0.25rem 0.5rem;
    background: none;
    border: none;
    font-size: 0.78rem;
