    border-radius: 4px;
    white-space: nowrap;
    transition: background 0.1s;
}

.action-btn:hover {
    background: #eef1f5;
}

.emoji-picker-wrapper {
    position: relative;
}

.emoji-picker {
    position: absolute;
    top: 100%;
    right: 0;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #dce0e5;
    border-radius: 6px;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    z-index: 20;
}

.emoji-option {
    padding: 0.3rem 0.4rem;
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    border-radius: 4px;
    transition: background 0.1s;
}

.emoji-option:hover {
    background: #eef1f5;
}

