@using sv_151efc2849d444ab8524542c866939c8.Services

<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <MessageItem Message="RootMessage" ShowHoverActions="false" />
        </div>

        <div class="thread-replies">
            @if (Replies.Count > 0)
            {
                <div class="reply-divider">@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</div>
            }

            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply" ShowHoverActions="false" />
            }
        </div>

        <MessageInput Placeholder="Reply…" ButtonLabel="Reply" OnSubmit="OnSendReply" />
    }
</div>

@code {
    [Parameter, EditorRequired] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public IReadOnlyList<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }
}

.thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

.close-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #72767d;
    border-radius: 4px;
    padding: 0.15rem 0.4rem;
    transition: background 0.12s;
}

.close-btn:hover {
    background: #eef1f5;
    color: #2c2f33;
}

.thread-root {
    border-bottom: 1px solid #e0e0e0;
    background: #f8f9fa;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 0.25rem 0;
}

.reply-divider {
    padding: 0.4rem 1rem;
    font-size: 0.75rem;
    font-weight: 600;
    color: #96989d;
    border-bottom: 1px solid #eef1f5;
}

