@page "/chat"
@using sv_151efc2849d444ab8524542c866939c8.Services
@rendermode InteractiveServer
@inject IChatService ChatService
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="activeChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(isThreadOpen ? "with-thread" : "")">
        @if (activeChannel is not null)
        {
            <MessageArea ChannelName="@activeChannel.Name"
                         ChannelDescription="@activeChannel.Description"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoadingMore="isLoadingMore"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnSendMessage="SendMessage"
                         OnLoadMore="LoadOlderMessages" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (isThreadOpen && threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private List<ThreadSummary> threadSummaries = [];
    private List<Message> threadReplies = [];

    private Channel? activeChannel;
    private int? activeChannelId;
    private Message? threadRootMessage;
    private bool isThreadOpen;
    private bool isLoadingMore;

    private const int PageSize = 30;

    private IJSObjectReference? scrollModule;
    private DotNetObjectReference<ChatPage>? selfRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            selfRef = DotNetObjectReference.Create(this);
            scrollModule = await JS.InvokeAsync<IJSObjectReference>(
                "import", "./_content/sv-151efc2849d444ab8524542c866939c8/Pages/Chat/ChatPage.razor.js");
            await scrollModule.InvokeVoidAsync("initScrollDetection", ".message-list", selfRef);
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await LoadOlderMessages();
    }

    private async Task SelectChannel(int channelId)
    {
        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        threadSummaries = [];

        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
            await ChatService.MarkChannelReadAsync(channelId);
            await RefreshThreadSummaries();

            // Refresh channel list to update unread counts
            channels = await ChatService.GetChannelsAsync();
        }
    }

    private async Task LoadOlderMessages()
    {
        if (isLoadingMore || activeChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId.Value, messages.Count, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            await RefreshThreadSummaries();
        }

        isLoadingMore = false;
    }

    private async Task SendMessage(string content)
    {
        if (activeChannelId is null) return;

        var msg = await ChatService.SendMessageAsync(activeChannelId.Value, content, null);
        messages.Add(msg);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        var thread = await ChatService.GetThreadAsync(messageId);
        threadReplies = thread.Where(m => m.Id != messageId).ToList();
        isThreadOpen = true;
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannelId is null || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, content, threadRootMessage.Id);
        threadReplies.Add(reply);
        await RefreshThreadSummaries();
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Refresh messages to reflect the new reaction
        if (activeChannelId is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannelId.Value, 0, messages.Count);
        }
    }

    private async Task RefreshThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var rootIds = messages
            .Where(m => m.ReplyToId is null)
            .Select(m => m.Id)
            .ToHashSet();

        var summaries = new List<ThreadSummary>();
        foreach (var rootId in rootIds)
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(rootId);
                var replies = thread.Where(m => m.Id != rootId).ToList();
                if (replies.Count > 0)
                {
                    summaries.Add(new ThreadSummary(rootId, replies.Count, replies.Max(r => r.SentAt)));
                }
            }
            catch
            {
                // Thread may not exist or have no replies
            }
        }

        threadSummaries = summaries;
    }

    public async ValueTask DisposeAsync()
    {
        if (scrollModule is not null)
        {
            try
            {
                await scrollModule.InvokeVoidAsync("dispose");
                await scrollModule.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit already closed
            }
        }

        selfRef?.Dispose();
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    transition: flex 0.2s ease;
}

.chat-main.with-thread {
    flex: 0 0 55%;
}

.chat-thread {
    width: 25%;
    min-width: 250px;
    flex-shrink: 0;
}

.no-channel {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #96989d;
    font-size: 1.1rem;
}

let observer = null;
let element = null;

export function initScrollDetection(selector, dotNetRef) {
    element = document.querySelector(selector);
    if (!element) return;

    // Use an IntersectionObserver on a sentinel element at the top
    const sentinel = document.createElement('div');
    sentinel.className = 'scroll-sentinel';
    sentinel.style.height = '1px';
    element.prepend(sentinel);

    observer = new IntersectionObserver(
        (entries) => {
            if (entries[0].isIntersecting) {
                dotNetRef.invokeMethodAsync('OnScrolledToTop');
            }
        },
        { root: element, threshold: 1.0 }
    );

    observer.observe(sentinel);
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

